#include<bits/stdc++.h>
using namespace std;

void solve(){
    string a;
    long long ans=0,k;
    cin>>k;
    cin>>a;
    for(int i=0;i<a.size();i++){
        if(a[i]<='9') ans+=((a[i]-'0')*pow(k,a.size()-i-1));
        else ans+=((a[i]-'A'+10)*pow(k,a.size()-i-1));
    }
    cout<<ans<<"\n";
}
int main(){
    int t;
    cin>>t;
    while(t--){
        solve();
    }
}
